// Read the file binary from the upstream Read brand voice node and
// convert to UTF-8 text. n8n's helper handles whatever internal storage
// mode the binary is using (memory, filesystem, S3).

const buf = await this.helpers.getBinaryDataBuffer(0, 'data');
const systemPrompt = buf.toString('utf-8');

return [{ json: { systemPrompt } }];

// Read the topics.json binary from the upstream Read topics node,
// convert to UTF-8 text, parse as JSON. Output: $json is the parsed
// { renter: [...], owner: [...], service: [...] } object.

const buf = await this.helpers.getBinaryDataBuffer(0, 'data');
const allTopics = JSON.parse(buf.toString('utf-8'));

return [{ json: allTopics }];

// Day-of-week language rotation with weekly random shuffle.
// Same week → same Mon-Sun pattern; new week → fresh pattern.
// Weekly distribution: 3 ru + 2 ro + 2 en (43% / 29% / 29%).
// Seed: ISO year × 100 + ISO week number, so the rotation is deterministic
// per week but unpredictable across weeks.

const now = new Date();

function getISOWeek(d) {
  const date = new Date(Date.UTC(d.getFullYear(), d.getMonth(), d.getDate()));
  date.setUTCDate(date.getUTCDate() + 4 - (date.getUTCDay() || 7));
  const yearStart = new Date(Date.UTC(date.getUTCFullYear(), 0, 1));
  return Math.ceil((((date - yearStart) / 86400000) + 1) / 7);
}

const weekNum = getISOWeek(now);
const year = now.getUTCFullYear();
const seed = year * 100 + weekNum;

// Seeded PRNG (mulberry32) — deterministic for a given seed.
function mulberry32(s) {
  return function () {
    let t = s += 0x6D2B79F5;
    t = Math.imul(t ^ t >>> 15, t | 1);
    t ^= t + Math.imul(t ^ t >>> 7, t | 61);
    return ((t ^ t >>> 14) >>> 0) / 4294967296;
  };
}

const rng = mulberry32(seed);

// Weekly slot pool: 3 ru + 2 ro + 2 en = 7 days.
const pool = ['ru', 'ru', 'ru', 'ro', 'ro', 'en', 'en'];

// Fisher-Yates shuffle with seeded RNG → same week always shuffles the same way.
for (let i = pool.length - 1; i > 0; i--) {
  const j = Math.floor(rng() * (i + 1));
  [pool[i], pool[j]] = [pool[j], pool[i]];
}

// Map JS day (0=Sun..6=Sat) to ISO day-of-week (0=Mon..6=Sun).
const jsDay = now.getDay();
const dayIndex = (jsDay + 6) % 7;
const language = pool[dayIndex];

return [{
  json: {
    language,
    _rotation: { weekNum, year, dayIndex, weeklyPlan: pool }
  }
}];

// Weighted random pick: 40% renter, 40% owner, 20% service.
// Preserves `language` from the upstream Pick language node.

const language = $input.first().json.language;

const weights = { renter: 0.4, owner: 0.4, service: 0.2 };
const r = Math.random();

let perspective;
if (r < weights.renter) {
  perspective = 'renter';
} else if (r < weights.renter + weights.owner) {
  perspective = 'owner';
} else {
  perspective = 'service';
}

return [{ json: { perspective, language } }];

// Renter perspective — topics loaded from prompts/topics.json
// via Read topics + Extract topics JSON nodes. The extract node puts the
// parsed JSON at $json (root), so $('Extract topics JSON').first().json
// is the { renter, owner, service } object directly.

const allTopics = $('Extract topics JSON').first().json;
const topics = allTopics.renter;
const topic = topics[Math.floor(Math.random() * topics.length)];

return [{
  json: {
    perspective: 'renter',
    language: $input.first().json.language,
    selectedTopic: topic
  }
}];

// Owner perspective — topics loaded from prompts/topics.json
// via Read topics + Extract topics JSON nodes. The extract node puts the
// parsed JSON at $json (root), so $('Extract topics JSON').first().json
// is the { renter, owner, service } object directly.

const allTopics = $('Extract topics JSON').first().json;
const topics = allTopics.owner;
const topic = topics[Math.floor(Math.random() * topics.length)];

return [{
  json: {
    perspective: 'owner',
    language: $input.first().json.language,
    selectedTopic: topic
  }
}];

// Service perspective — topics loaded from prompts/topics.json
// via Read topics + Extract topics JSON nodes. The extract node puts the
// parsed JSON at $json (root), so $('Extract topics JSON').first().json
// is the { renter, owner, service } object directly.

const allTopics = $('Extract topics JSON').first().json;
const topics = allTopics.service;
const topic = topics[Math.floor(Math.random() * topics.length)];

return [{
  json: {
    perspective: 'service',
    language: $input.first().json.language,
    selectedTopic: topic
  }
}];

// Build prompts — embeds the multi-language brand-voice system prompt
// (loaded from prompts/brand-voice-system.md via Read brand voice +
// Extract brand voice text nodes) and assembles the Groq request body.

const perspective = $input.first().json.perspective;
const topic = $input.first().json.selectedTopic;
const language = $input.first().json.language;

// City names per language. Topic data uses Russian (Cyrillic); we translate
// on the fly so the user prompt instructs Groq with the right spelling.
const cityMap = {
  'Кишинёв': { ru: 'Кишинёв', ro: 'Chișinău', en: 'Chișinău' },
  'Бельцы':  { ru: 'Бельцы',  ro: 'Bălți',    en: 'Bălți' },
  'Кагул':   { ru: 'Кагул',   ro: 'Cahul',    en: 'Cahul' },
  'Тирасполь': { ru: 'Тирасполь', ro: 'Tiraspol', en: 'Tiraspol' },
  'Комрат':  { ru: 'Комрат',  ro: 'Comrat',   en: 'Comrat' },
  'Орхей':   { ru: 'Орхей',   ro: 'Orhei',    en: 'Orhei' },
  'Молдова': { ru: 'Молдова', ro: 'Moldova',  en: 'Moldova' }
};
const langLabel = { ru: 'Russian', ro: 'Romanian', en: 'English' }[language];
const city = (cityMap[topic.city] && cityMap[topic.city][language]) || topic.city;

// Extract from File (operation=text) puts the text content at json.data.
const systemPrompt = $('Extract brand voice text').first().json.systemPrompt;

const userPrompt = `Perspective: ${perspective}
Archetype: ${topic.archetype}
Topic: ${topic.description}
Language: ${langLabel} — write the ENTIRE post in ${langLabel}. The topic description above is in Russian for our internal reference; translate the idea into ${langLabel} with correct grammar, idiom, and the per-language formality rule.
City to reference: ${city}

Write ONE post in the ${perspective} perspective, following all mandatory rules and the feature whitelist. Vary the structure from previous outputs — do not reuse phrases from the example posts verbatim.

If the topic mentions multiple items (e.g. "drill, tent, suitcase"), pick ONE and stay with it for the entire post — do not jump between items mid-post.`;

return [{
  json: {
    perspective,
    language,
    selectedTopic: topic,
    requestBody: {
      model: 'llama-3.3-70b-versatile',
      temperature: 1.0,
      messages: [
        { role: 'system', content: systemPrompt },
        { role: 'user', content: userPrompt }
      ]
    }
  }
}];

// Deterministic post-validation. Universal checks (brand name, length,
// emoji, CJK) run for every language. Russian-specific style checks
// (Вы/ВЫ/вы/ты, forbidden phrases, mixed Latin city names) only run on
// language === 'ru'. For ro/en, we also check that no stray Cyrillic
// characters leaked into the body.
//
// If anything fails, builds a regenRequestBody = original conversation +
// assistant draft + user message listing the issues. IF node branches on
// _validate.passed.

const content = $input.first().json.choices[0].message.content;
const requestBody = $('Build prompts').first().json.requestBody;
const perspective = $('Build prompts').first().json.perspective;
const language = $('Build prompts').first().json.language;

const issues = [];

// ─── Universal checks (all languages) ───

// 1. Brand name must appear, written exactly as 'Lorent Bloom'
if (!content.includes('Lorent Bloom')) {
  issues.push('Brand name "Lorent Bloom" missing from the post — it must appear in the body, exactly as "Lorent Bloom" (not transliterated).');
}

// 2. Length (target 80-150, tolerate 60-200)
const wordCount = content.trim().split(/\s+/).filter(w => w.length > 0).length;
if (wordCount < 60) issues.push(`Too short: ${wordCount} words (target 80-150, minimum 60).`);
if (wordCount > 200) issues.push(`Too long: ${wordCount} words (target 80-150, max 200).`);

// 3. Emoji forbidden in any language
const emojiPattern = /[\u{1F300}-\u{1FAFF}\u{2600}-\u{27BF}\u{1F000}-\u{1F02F}\u{1F0A0}-\u{1F0FF}\u{1F100}-\u{1F1FF}\u{1F200}-\u{1F2FF}\u{2700}-\u{27BF}\u{2B50}\u{2B55}\u{2705}\u{274C}]/u;
if (emojiPattern.test(content)) {
  issues.push('Emoji detected — brand voice forbids ALL emojis (decorative or functional). Use plain text.');
}

// 4. CJK / foreign script token leak (Llama bug — '找到', '挂', etc.)
const cjkPattern = /[一-鿿぀-ヿ]/;
if (cjkPattern.test(content)) {
  issues.push('Foreign script characters (Chinese/Japanese) detected — likely Llama token leak. Use only the target language alphabet.');
}

// ─── Russian-only checks ───

if (language === 'ru') {
  // Lowercase 'вы'
  const lowerVyPattern = /(^|[\s,.;:!?\-—«"])вы(\s|[,.;:!?\-—»"])/;
  if (lowerVyPattern.test(content)) {
    issues.push('Lowercase "вы" detected — formal address must always be capitalized "Вы" (capital В then lowercase ы).');
  }
  // ALL-CAPS 'ВЫ'
  if (/(^|[\s,.;:!?\-—«"])ВЫ(\s|[,.;:!?\-—»"])/.test(content)) {
    issues.push('ALL-CAPS "ВЫ" detected — should be "Вы" (capital В then lowercase ы).');
  }
  // Informal 'ты'
  if (/(^|[\s,.;:!?\-—«"])ты(\s|[,.;:!?\-—»"])/i.test(content)) {
    issues.push('Informal "ты" detected — brand voice requires formal "Вы" throughout, never "ты".');
  }

  // Forbidden Russian phrases
  const forbidden = [
    { rx: /С помощью нашей платформы/i, name: '"С помощью нашей платформы" (use "В Lorent Bloom" instead)' },
    { rx: /часто возникает необходимость/i, name: '"часто возникает необходимость" (open with a concrete fact instead)' },
    { rx: /многие сталкиваются с/i, name: '"многие сталкиваются с"' },
    { rx: /Это разумное решение для тех/i, name: '"Это разумное решение для тех..."' },
    { rx: /Это поможет (Вам|вам) сэкономить/i, name: '"Это поможет Вам сэкономить"' },
    { rx: /(^|\s)успейте/i, name: '"успейте" (no urgency cliches)' },
    { rx: /не упустите/i, name: '"не упустите"' },
    { rx: /ограниченное предложение/i, name: '"ограниченное предложение"' },
    { rx: /тысячи (пользователей|людей)/i, name: '"тысячи пользователей/людей" (no fabricated stats)' },
    { rx: /самый безопасный/i, name: '"самый безопасный" (no unprovable superlatives)' },
    { rx: /лучший в Молдове/i, name: '"лучший в Молдове" (no unprovable superlatives)' },
    { rx: /наша платформа/i, name: '"наша платформа" (use "Lorent Bloom" instead)' },
    { rx: /многие пользователи/i, name: '"многие пользователи" — implied user count without basis' },
    { rx: /около \d+\s*лей в день/i, name: '"около X лей в день" — vague price, use a specific number tied to a real item' },
    { rx: /безделушк[аи]/i, name: '"безделушки" — dismissive of real items; use specific item names' }
  ];
  for (const { rx, name } of forbidden) {
    if (rx.test(content)) issues.push(`Forbidden phrase: ${name}`);
  }

  // Mixed-script in ru post: Latin city names are wrong
  const latinCities = ['Chișinău', 'Bălți', 'Cahul', 'Tiraspol', 'Comrat'];
  for (const lc of latinCities) {
    if (content.includes(lc)) {
      issues.push(`Mixed script: "${lc}" (Latin) in a Russian post — use Cyrillic equivalent.`);
    }
  }
}

// ─── Romanian-only checks ───

if (language === 'ro') {
  // Stray Cyrillic in a Latin-script post
  if (/[Ѐ-ӿ]/.test(content)) {
    issues.push('Cyrillic characters detected in a Romanian post — write entirely in Latin script with Romanian diacritics.');
  }
  // 'tu' as informal you (light check — bounded by spaces to reduce false positives)
  if (/(^|[\s,.;:!?\-—«"])tu(\s|[,.;:!?\-—»"])/.test(content)) {
    issues.push('Informal "tu" detected — brand voice requires formal "Dvs." / "Dumneavoastră", never "tu".');
  }
}

// ─── English-only checks ───

if (language === 'en') {
  // Stray Cyrillic in a Latin-script post
  if (/[Ѐ-ӿ]/.test(content)) {
    issues.push('Cyrillic characters detected in an English post — write entirely in Latin script.');
  }
  // Contractions — flag the common ones for the formal register
  const contractions = [/\bdon't\b/i, /\bcan't\b/i, /\bwon't\b/i, /\bit's\b/i, /\byou're\b/i, /\bthey're\b/i, /\bwe're\b/i];
  for (const rx of contractions) {
    if (rx.test(content)) {
      issues.push(`Contraction "${content.match(rx)[0]}" — formal register prefers the expanded form (do not, cannot, will not, it is, you are, they are, we are).`);
      break;
    }
  }
}

const passed = issues.length === 0;
let regenRequestBody = null;

if (!passed) {
  const fixInstruction = `The draft you just wrote has these brand-voice issues:

${issues.map((iss, i) => `${i + 1}. ${iss}`).join('\n')}

Rewrite the post fixing EVERY issue. Keep the same topic, perspective (${perspective}), language (${language}), and approximate length. Output ONLY the corrected post — no commentary, no labels, no "Here is the corrected post:".`;

  regenRequestBody = {
    ...requestBody,
    messages: [
      ...requestBody.messages,
      { role: 'assistant', content },
      { role: 'user', content: fixInstruction }
    ]
  };
}

return [{
  json: {
    choices: $input.first().json.choices,
    _validate: {
      passed,
      issues,
      wordCount,
      language,
      regenRequestBody
    }
  }
}];

// Compose preview — loop-tolerant. Builds captionText and packages the
// binary image for the Telegram preview. Handles five upstream sources:
//   1. Cloudflare image generation (initial / regen_both): item.json.result.image
//   2. Regen image with hint: item.json.result.image (same shape as #1)
//   3. Regen text with hint: item.json.choices (no result.image — reuse prior image)
//   4. Override text from form: item.json.overrideText (reuse prior image)
//   5. Wire downloaded as image: item.binary.image is the new upload (reuse prior text)

const item = $input.first();
const inJson = item.json || {};
const inBinary = item.binary || {};

// ─── Text source resolution ───
let text;
if (inJson.overrideText) {
  text = inJson.overrideText;
} else if (inJson.choices && inJson.choices[0]) {
  text = inJson.choices[0].message.content;
} else {
  try {
    text = $('Merge text branches').first().json.choices[0].message.content;
  } catch (e) {
    text = null;
  }
  if (!text) {
    try {
      text = $('Compose preview').first().json.text;
    } catch (e) {}
  }
}

if (!text) throw new Error('Compose preview: no text source available');

// ─── Image source resolution ───
let imageBinary;
let _imageSource;
let _inBinaryKeys = Object.keys(inBinary);
let _inJsonShape = {
  hasResultImage: !!(inJson.result && inJson.result.image),
  hasChoices: !!(inJson.choices && inJson.choices[0]),
  hasOverrideText: !!inJson.overrideText,
  action: inJson.action || null,
  new_image_url: inJson.new_image_url || null
};

if (inJson.result && inJson.result.image) {
  imageBinary = {
    data: inJson.result.image,
    mimeType: 'image/png',
    fileName: 'generated.png'
  };
  _imageSource = 'cloudflare_response';
} else if (inBinary.image) {
  imageBinary = inBinary.image;
  _imageSource = 'inline_binary_image_key';
} else {
  // Maybe upstream put binary under a non-image key
  const firstBinKey = _inBinaryKeys[0];
  if (firstBinKey) {
    imageBinary = inBinary[firstBinKey];
    _imageSource = 'inline_binary_first_key:' + firstBinKey;
  } else {
    try {
      const prior = $('Compose preview').first();
      if (prior.binary && prior.binary.image) {
        imageBinary = prior.binary.image;
        _imageSource = 'historic_compose_preview';
      }
    } catch (e) {}
  }
}

if (!imageBinary) throw new Error('Compose preview: no image source available. inBinaryKeys=' + JSON.stringify(_inBinaryKeys));

// ─── Context (perspective, topic, language) ───
let perspective = inJson.perspective;
let topic = inJson.selectedTopic;
let language = inJson.language;
if (!perspective || !topic || !language) {
  const bp = $('Build prompts').first().json;
  perspective = perspective || bp.perspective;
  topic = topic || bp.selectedTopic;
  language = language || bp.language;
}

// ─── Hashtag composition (recomputed each iteration for variety) ───
const hashtags = ['#LorentBloom'];

const brandTag = {
  ru: '#АрендаМолдова',
  ro: '#ÎnchirieriMoldova',
  en: '#RentMoldova'
}[language];
hashtags.push(brandTag);

const perspectiveTags = {
  renter:  { ru: '#АрендуйВМолдове', ro: '#ÎnchiriazăÎnMoldova', en: '#RentInMoldova' },
  owner:   { ru: '#СдайВАренду',     ro: '#DăÎnChirie',           en: '#EarnRenting' },
  service: null
};
const ptag = perspectiveTags[perspective] && perspectiveTags[perspective][language];
if (ptag) hashtags.push(ptag);

if (language === 'ru') {
  const topicTags = topic.hashtags || [];
  const shuffled = [...topicTags].sort(() => Math.random() - 0.5);
  hashtags.push(...shuffled.slice(0, Math.min(2, shuffled.length)));
} else {
  hashtags.push('#Moldova');
}

const captionText = text + '\n\nhttps://lorentbloom.com\n\n' + hashtags.join(' ');

return [{
  json: {
    perspective,
    language,
    selectedTopic: topic,
    text,
    captionText,
    hashtagsUsed: hashtags,
    _debug: { imageSource: _imageSource, inBinaryKeys: _inBinaryKeys, inJsonShape: _inJsonShape, imageBinarySize: imageBinary && imageBinary.fileSize }
  },
  binary: { image: imageBinary }
}];

// Parse the webhook body sent by the Telegram action handler chain.
// Body shape:
//   { action: 'approve|regen_image|regen_text|regen_both|edit_text|replace_image',
//     feedback: '' | '...',     // for regen_* if user provided a hint
//     new_text: '' | '...',     // for edit_text
//     new_image_url: '' | 'https://...'  // for replace_image (Catbox URL handler uploaded)
//   }
//
// Carries forward the pre-Wait state (caption, binary, topic, language) from
// the most recent Compose preview execution so every downstream branch has
// a full item to work with.

const item = $input.first();
// Wait node webhook resume puts the body on item.json.body (n8n v1.x) — fall back to item.json.
const body = (item.json && item.json.body) ? item.json.body : (item.json || {});

const action = body.action || 'invalid';
const feedback = body.feedback || '';
const new_text = body.new_text || '';
const new_image_url = body.new_image_url || '';

const validActions = ['approve', 'regen_image', 'regen_text', 'regen_both', 'edit_text', 'replace_image'];
let normalizedAction = action;
let validationError = null;

if (!validActions.includes(action)) {
  normalizedAction = 'invalid';
  validationError = `Unknown action received: ${action}`;
}

// Pre-Wait state from the most recent Compose preview execution.
const composePreview = $('Compose preview').first();

const outputJson = {
  action: normalizedAction,
  feedback,
  new_text,
  new_image_url,
  validationError,
  perspective: composePreview.json.perspective,
  language: composePreview.json.language,
  selectedTopic: composePreview.json.selectedTopic,
  captionText: composePreview.json.captionText,
  hashtagsUsed: composePreview.json.hashtagsUsed
};

if (normalizedAction === 'invalid') {
  outputJson.captionText = '[Invalid action: ' + validationError + ']\n\n' + outputJson.captionText;
}

const outputBinary = {};
if (composePreview.binary && composePreview.binary.image) {
  outputBinary.image = composePreview.binary.image;
}

return [{ json: outputJson, binary: outputBinary }];

// Override text from form (edit_text path).
// User-typed text becomes the new post body; Compose preview will append
// the URL and hashtags via the overrideText path.

const item = $input.first();
const newText = (item.json.new_text || '').trim();

if (!newText) {
  throw new Error('Override text from form: new_text is empty (should have been caught by Parse resume payload).');
}

return [{
  json: {
    ...item.json,
    overrideText: newText
  },
  binary: item.binary
}];

// Read the actual file bytes downloaded by Fetch new image, base64-encode
// them, and embed in the binary metadata's `data` field directly. This
// avoids n8n's binary-by-reference path which loses the file reference
// when binary keys get reassigned across Code nodes.
//
// Same pattern Cloudflare image gen uses (its base64 output flows fine
// through subsequent nodes), so we mirror it here.

const buf = await this.helpers.getBinaryDataBuffer(0, 'data');
const base64 = buf.toString('base64');

const ctx = $('Parse resume payload').first();

return [{
  json: ctx.json,
  binary: {
    image: {
      data: base64,
      mimeType: 'image/jpeg',
      fileName: 'uploaded.jpg'
    }
  }
}];

// Handle a callback_query (button tap on the preview message).
// - Verifies the tap matches the currently-pending review (rejects stale buttons).
// - For 'approve': clears pending and routes to resume the generator immediately.
// - For 'regen_*' / 'edit_text' / 'replace_image': records waitingFor in static
//   data and routes to a Telegram sendMessage that asks for the input.

const cb = $input.first().json.callback_query;
const action = (cb && cb.data) || null;
const messageId = cb && cb.message && cb.message.message_id;
const chatId = cb && cb.message && cb.message.chat && cb.message.chat.id;
const callbackQueryId = cb && cb.id;

const data = $getWorkflowStaticData('global');
const pending = data.pending;

// Reject stale or mismatched taps.
if (!pending || pending.messageId !== messageId || pending.chatId !== chatId) {
  let reason;
  if (!pending) {
    reason = 'pending is null/missing in staticData — Save pending state did not write or write was lost';
  } else if (pending.messageId !== messageId) {
    reason = `messageId mismatch: button=${messageId} (type ${typeof messageId}) vs pending=${pending.messageId} (type ${typeof pending.messageId})`;
  } else if (pending.chatId !== chatId) {
    reason = `chatId mismatch: button=${chatId} (type ${typeof chatId}) vs pending=${pending.chatId} (type ${typeof pending.chatId})`;
  }
  return [{
    json: {
      _nextStep: 'ignore',
      reason,
      callbackQueryId,
      buttonChatId: chatId,
      buttonMessageId: messageId,
      pendingSnapshot: pending
    }
  }];
}

let nextStep, askText, waitingFor, resumeBody;

if (action === 'approve') {
  nextStep = 'resume';
  resumeBody = { action: 'approve' };
  data.pending = null;
} else if (action === 'regen_image' || action === 'regen_text' || action === 'regen_both') {
  nextStep = 'ask';
  waitingFor = 'hint_for_' + action;
  askText = 'Send a short style hint as a text reply (e.g. "darker, no people" or "shorter, more direct"), or send /skip to regenerate without a hint.';
  data.pending.waitingFor = waitingFor;
} else if (action === 'edit_text') {
  nextStep = 'ask';
  waitingFor = 'edit_text';
  askText = 'Send the new caption as a text reply. It will replace the current post body verbatim (URL and hashtags get re-added automatically).';
  data.pending.waitingFor = waitingFor;
} else if (action === 'replace_image') {
  nextStep = 'ask';
  waitingFor = 'replace_image';
  askText = 'Send the new image as a photo in this chat. It will replace the current preview image.';
  data.pending.waitingFor = waitingFor;
} else {
  nextStep = 'ignore';
  return [{
    json: {
      _nextStep: 'ignore',
      reason: 'Unknown callback_data: ' + action,
      callbackQueryId,
      chatId
    }
  }];
}

return [{
  json: {
    _nextStep: nextStep,
    callbackQueryId,
    chatId,
    askText,
    waitingFor,
    resumeUrl: pending.resumeUrl,
    resumeBody
  }
}];

// Handle a message update (text reply or photo).
// - If no pending review is waiting for input, ignores.
// - If pending.waitingFor matches the message kind, builds a resume payload
//   and routes to the resume HTTP. Clears waitingFor afterward.
//
// waitingFor values:
//   'edit_text'           — expect text → resume with {action:'edit_text', new_text}
//   'hint_for_regen_*'    — expect text → resume with {action:'regen_*', feedback}
//                            (text '/skip' → feedback='')
//   'replace_image'       — expect photo → fetch file → upload to Catbox → resume
//                            with {action:'replace_image', new_image_url}

const msg = $input.first().json.message;
const text = msg && msg.text;
const photo = msg && msg.photo;
const chatId = msg && msg.chat && msg.chat.id;

const data = $getWorkflowStaticData('global');
const pending = data.pending;

if (!pending || !pending.waitingFor) {
  return [{ json: { _nextStep: 'ignore', reason: 'No pending review waiting for input.' } }];
}
if (pending.chatId !== chatId) {
  return [{ json: { _nextStep: 'ignore', reason: 'Message from a different chat.' } }];
}

const waitingFor = pending.waitingFor;

if (waitingFor === 'edit_text') {
  if (!text) return [{ json: { _nextStep: 'ignore', reason: 'edit_text expected a text reply.' } }];
  data.pending = null;
  return [{
    json: {
      _nextStep: 'resume_text',
      resumeUrl: pending.resumeUrl,
      resumeBody: { action: 'edit_text', new_text: text }
    }
  }];
}

if (waitingFor.startsWith('hint_for_')) {
  if (!text) return [{ json: { _nextStep: 'ignore', reason: 'Hint expected a text reply.' } }];
  const action = waitingFor.replace('hint_for_', '');
  const feedback = text.trim() === '/skip' ? '' : text;
  data.pending = null;
  return [{
    json: {
      _nextStep: 'resume_text',
      resumeUrl: pending.resumeUrl,
      resumeBody: { action, feedback }
    }
  }];
}

if (waitingFor === 'replace_image') {
  if (!photo || photo.length === 0) {
    return [{ json: { _nextStep: 'ignore', reason: 'replace_image expected a photo.' } }];
  }
  const file_id = photo[photo.length - 1].file_id; // largest size
  data.pending = null;
  return [{
    json: {
      _nextStep: 'resume_image',
      resumeUrl: pending.resumeUrl,
      file_id
    }
  }];
}

return [{ json: { _nextStep: 'ignore', reason: 'Unknown waitingFor: ' + waitingFor } }];

// Write the pending state to workflow staticData.
// This runs as its own execution (triggered by the local HTTP call from
// Save pending state), so when this execution completes, staticData
// is flushed to disk and visible to the Telegram trigger execution.

const body = $input.first().json.body || $input.first().json;

const data = $getWorkflowStaticData('global');
data.pending = {
  resumeUrl: body.resumeUrl,
  messageId: body.messageId,
  chatId: body.chatId,
  waitingFor: null,
  registeredAt: new Date().toISOString()
};

return [{ json: { ok: true, pending: data.pending } }];

